// Inputs (from caller):
//   workflow_name: 'WF_TOPICS_GENERATE' | 'WF_SCRIPT_PASS' | ...
//   country_target: 'GENERAL' | 'AU' | future
//   prompt_stage: 'pass1' | 'pass2' | 'pass3' | 'evaluator' | 'topic_master' | etc.
//
// Output: { primary_key, fallback_key, lookup_url }

const input = $input.first().json;
const workflow = (input.workflow_name || '').toUpperCase();
const country = (input.country_target || 'GENERAL').toUpperCase();
const stage = (input.prompt_stage || '').toLowerCase();

// Map (workflow, stage) -> base prompt_type
const baseKey = (() => {
  if (workflow === 'WF_TOPICS_GENERATE') return 'topic_generator_master';
  if (workflow === 'WF_SCRIPT_PASS') {
    if (stage === 'pass1') return 'script_pass1';
    if (stage === 'pass2') return 'script_pass2';
    if (stage === 'pass3') return 'script_pass3';
    if (stage === 'evaluator') return 'script_evaluator';
    if (stage === 'retry') return 'script_retry_template';
    if (stage === 'metadata_extractor') return 'script_metadata_extractor';
    return 'script_pass1';
  }
  if (workflow === 'WF_REGISTER_ANALYZE') return 'register_classify';
  if (workflow === 'WF_VIDEO_METADATA') {
    if (stage === 'title') return country === 'AU' ? 'seo_title_au' : 'seo_title';
    if (stage === 'description') return country === 'AU' ? 'seo_desc_au' : 'seo_desc';
    if (stage === 'tags') return country === 'AU' ? 'seo_tags_au' : 'seo_tags';
    return 'video_metadata';
  }
  if (workflow === 'WF_THUMBNAIL_GENERATE') {
    if (stage === 'concept') return country === 'AU' ? 'thumb_concept_au' : 'thumbnail_concept';
    if (stage === 'prompt') return country === 'AU' ? 'thumb_prompt_au' : 'thumbnail_prompt';
    return 'thumbnail_concept';
  }
  if (workflow === 'WF_TOPIC_INTELLIGENCE') {
    if (stage === 'discover') return country === 'AU' ? 'topic_discover_au' : null;
    if (stage === 'event') return country === 'AU' ? 'topic_event_au' : null;
    if (stage === 'gap_score') return country === 'AU' ? 'gap_score_au' : null;
    return null;
  }
  if (workflow === 'WF_DEMONETIZATION_AUDIT') {
    return country === 'AU' ? 'demon_audit_au' : null;
  }
  if (workflow === 'WF_COMPETITOR_ANALYZER') {
    if (stage === 'channel') return country === 'AU' ? 'swot_channel_au' : null;
    if (stage === 'subniche') return country === 'AU' ? 'swot_subniche_au' : null;
    return null;
  }
  if (workflow === 'WF_COACH_REPORT') {
    return country === 'AU' ? 'coach_monthly_au' : null;
  }
  if (workflow === 'WF_ANALYTICS_CRON' && stage === 'retention') {
    return country === 'AU' ? 'retention_analyze_au' : null;
  }
  return null;
})();

if (!baseKey) {
  return [{ json: { error: 'No prompt mapping for ' + workflow + '/' + stage + '/' + country, primary_key: null, fallback_key: null } }];
}

// Country-aware key resolution
// For prompts that have a _au-suffixed sibling (script_pass1_au), prefer that
// when country='AU'. For shared prompts (topic_generator_master) the country
// content arrives via the 4 slot variables — same key for all countries.
let primaryKey = baseKey;
let fallbackKey = baseKey;

if (country === 'AU') {
  const auKey = baseKey + '_au';
  // For these specific prompts, _au sibling exists; otherwise use the General master + slots
  const HAS_AU_SIBLING = new Set([
    'topic_discover_au', 'topic_event_au', 'gap_score_au',
    'register_classify_au_addendum', 'demon_audit_au',
    'swot_channel_au', 'swot_subniche_au', 'retention_analyze_au',
    'coach_monthly_au', 'seo_title_au', 'seo_desc_au', 'seo_tags_au',
    'thumb_concept_au', 'thumb_prompt_au'
  ]);
  if (HAS_AU_SIBLING.has(baseKey)) {
    primaryKey = baseKey;
    fallbackKey = baseKey;
  }
  // For General masters (script_pass1/2/3, script_evaluator, topic_generator_master),
  // primaryKey = baseKey; the 4 country slot variables fill in AU content.
}

return [{ json: {
  workflow_name: workflow,
  country_target: country,
  prompt_stage: stage,
  primary_key: primaryKey,
  fallback_key: fallbackKey,
  lookup_url: 'https://supabase.operscale.cloud/rest/v1/system_prompts?prompt_type=eq.' + primaryKey + '&is_active=eq.true&select=prompt_type,prompt_text,version&limit=1'
} }];

const resolver = $('Build Resolver Inputs').first().json;
const rows = $input.first().json;
const row = Array.isArray(rows) && rows.length > 0 ? rows[0] : null;

if (!row) {
  return [{ json: {
    success: false,
    error: 'Prompt not found: ' + resolver.primary_key,
    primary_key: resolver.primary_key,
    country_target: resolver.country_target
  } }];
}

let promptText = row.prompt_text;
const PLACEHOLDER_RE = /\{country_(?:compliance_block|terminology_block|calendar_context|demonetization_constraints)\}/;

if (PLACEHOLDER_RE.test(promptText)) {
  try {
    const blocksRes = await fetch($env.SUPABASE_URL + '/rest/v1/rpc/render_country_blocks', {
      method: 'POST',
      headers: {
        apikey: $env.SUPABASE_ANON_KEY,
        Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ p_country_target: (resolver.country_target || 'GENERAL') })
    });
    if (blocksRes.ok) {
      const blocks = await blocksRes.json();
      promptText = promptText
        .replace(/\{country_compliance_block\}/g, (blocks.country_compliance_block || ''))
        .replace(/\{country_terminology_block\}/g, (blocks.country_terminology_block || ''))
        .replace(/\{country_calendar_context\}/g, (blocks.country_calendar_context || ''))
        .replace(/\{country_demonetization_constraints\}/g, (blocks.country_demonetization_constraints || ''));
    }
  } catch (e) {
    // On RPC failure, leave placeholders intact rather than silently stripping content.
    // Caller workflows can detect the literal {country_*} strings and surface a warning.
  }
}

return [{ json: {
  success: true,
  prompt_type: row.prompt_type,
  prompt_text: promptText,
  version: row.version,
  country_target: resolver.country_target,
  workflow_name: resolver.workflow_name,
  prompt_stage: resolver.prompt_stage
} }];
